const parts = [
  {
    text: "請根據這張人物照片，生成一張符合以下要求的角色圖：\n\n" +
      "【人物風格】\n" +
      "Cyberpunk pixel art portrait, glowing neon color palette, futuristic sci-fi vibe, " +
      "32-bit detailed pixel art, high contrast lighting, atmospheric neon glow, " +
      "retaining the subject's likeness and facial features accurately.\n\n" +
      "【背景風格】\n" +
      "背景以紅黑色系的數據破壞感為核心，融合末日議會、魷魚遊戲的視覺元素。" +
      "帶有數位隧道、矩陣代碼流、破碎的霓虹燈光效果。" +
      "整體營造出賽博龐克末日感，黑暗中帶有紅色霓虹光暈。\n\n" +
      "【重要規則】\n" +
      "1. 人物必須保留原照片的五官特徵和神韻\n" +
      "2. 不要加任何文字\n" +
      "3. 人物頭部位置在畫面上方 1/3 處\n" +
      "4. 風格統一，人物和背景要自然融合"
  }
];

// 加入所有參考圖片
for (let i = 0; i < items.length; i++) {
  const binaryKey = Object.keys(items[i].binary)[0];
  const binaryData = await this.helpers.getBinaryDataBuffer(i, binaryKey);
  parts.push({
    inline_data: {
      mime_type: items[i].binary[binaryKey].mimeType,
      data: binaryData.toString('base64')
    }
  });
}

const body = {
  contents: [{
    role: "user",
    parts
  }],
  systemInstruction: {
    parts: [{
      text: "你是一個專業的賽博龐克像素藝術生成器。" +
        "你的任務是將真人照片轉換成高品質的賽博龐克像素風角色圖。" +
        "必須嚴格保留人物的面部特徵、髮型和神韻。" +
        "背景使用紅黑色系的數位破壞感風格，帶有霓虹光暈和數據流元素。" +
        "整體色調以深黑、暗紅、霓虹紅為主，點綴少量青色霓虹。" +
        "不要生成任何文字或浮水印。"
    }]
  },
  generationConfig: {
    responseModalities: ["IMAGE"],
    imageConfig: {
      aspectRatio: "2:3",
      imageSize: "1K"
    }
  }
};

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash-exp:generateContent?key=AIzaSyAIeX6l753_VdDjq_mWfxQLl9PmiGvLnhc',
  body,
  json: true,
  timeout: 120000,
});

const imageData = response.candidates[0].content.parts[0].inlineData;
const buffer = Buffer.from(imageData.data, 'base64');

return [{
  json: { success: true },
  binary: {
    image: await this.helpers.prepareBinaryData(buffer, 'generated.png', imageData.mimeType)
  }
}];
